import{_ as a,a as t,b as r,c as o,d as i}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as d,o as n,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Adicionar canal OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/onedrive.md","filePath":"pt-BR/upload/onedrive.md","lastUpdated":1781962217000}'),l={name:"pt-BR/upload/onedrive.md"};function p(h,e,m,b,u,g){return n(),s("div",null,[...e[0]||(e[0]=[c('<h1 id="adicionar-canal-onedrive" tabindex="-1">Adicionar canal OneDrive <a class="header-anchor" href="#adicionar-canal-onedrive" aria-label="Permalink to &quot;Adicionar canal OneDrive&quot;">​</a></h1><p>O canal OneDrive usa o Microsoft OneDrive como destino de armazenamento.</p><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>Conta Microsoft</td><td>Gerenciar OneDrive e registro do app</td></tr><tr><td>Domínio ImgBed</td><td>Configurar callback OAuth</td></tr><tr><td>App registration</td><td>Obter Client ID e Client Secret</td></tr><tr><td>Refresh Token</td><td>Manter acesso de longo prazo</td></tr></tbody></table><h2 id="abrir-microsoft-entra-id" tabindex="-1">Abrir Microsoft Entra ID <a class="header-anchor" href="#abrir-microsoft-entra-id" aria-label="Permalink to &quot;Abrir Microsoft Entra ID&quot;">​</a></h2><ol><li>Abra <code>portal.azure.com</code>.</li><li>Pesquise <code>Microsoft Entra ID</code>.</li><li>Entre em <code>App registrations</code>.</li><li>Clique em <code>New registration</code>.</li></ol><h2 id="registrar-aplicacao" tabindex="-1">Registrar aplicação <a class="header-anchor" href="#registrar-aplicacao" aria-label="Permalink to &quot;Registrar aplicação&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Name</td><td>Por exemplo <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Conforme o tipo de OneDrive usado</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://seu-dominio/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Para OneDrive pessoal, escolha contas pessoais Microsoft. Para permitir contas pessoais e corporativas, escolha a opção compatível com ambos.</p><p><img src="'+a+'" alt="Registro OneDrive" loading="lazy"></p><p>Depois do registro, copie <code>Application (client) ID</code>. Para conta corporativa, guarde também <code>Directory (tenant) ID</code>.</p><p><img src="'+t+'" alt="Application ID e Tenant ID" loading="lazy"></p><h2 id="criar-client-secret" tabindex="-1">Criar Client Secret <a class="header-anchor" href="#criar-client-secret" aria-label="Permalink to &quot;Criar Client Secret&quot;">​</a></h2><ol><li>Abra <code>Certificates &amp; secrets</code>.</li><li>Clique em <code>New client secret</code>.</li><li>Defina nome e expiração.</li><li>Copie o <code>Value</code> imediatamente.</li></ol><p><img src="'+r+'" alt="Client Secret" loading="lazy"></p><p>Esse valor pode não aparecer de novo. Guarde ao criar.</p><h2 id="permissoes-microsoft-graph" tabindex="-1">Permissões Microsoft Graph <a class="header-anchor" href="#permissoes-microsoft-graph" aria-label="Permalink to &quot;Permissões Microsoft Graph&quot;">​</a></h2><p>Em <code>API permissions</code>, adicione delegated permissions do Microsoft Graph.</p><table tabindex="0"><thead><tr><th>Permissão</th><th>Uso</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Enviar, criar pastas e excluir arquivos</td></tr><tr><td><code>offline_access</code></td><td>Obter Refresh Token</td></tr><tr><td><code>User.Read</code></td><td>Ler informações da conta e capacidade</td></tr></tbody></table><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><p>Em Configurações de upload, escolha <code>OneDrive</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Por exemplo <code>OneDrive Main</code></td></tr><tr><td>Client ID</td><td><code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Value do Client Secret</td></tr><tr><td>Tenant ID</td><td>Veja a tabela abaixo</td></tr><tr><td>Refresh Token</td><td>Deixe vazio no início</td></tr><tr><td>Diretório raiz</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><p><img src="'+o+'" alt="Configuração OneDrive" loading="lazy"></p><table tabindex="0"><thead><tr><th>Tipo de conta</th><th>Tenant ID</th></tr></thead><tbody><tr><td>Conta pessoal</td><td><code>consumers</code></td></tr><tr><td>Pessoal + corporativa</td><td><code>common</code></td></tr><tr><td>Apenas organização atual</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h2 id="obter-refresh-token" tabindex="-1">Obter Refresh Token <a class="header-anchor" href="#obter-refresh-token" aria-label="Permalink to &quot;Obter Refresh Token&quot;">​</a></h2><ol><li>No ImgBed, clique em <code>Obter Token</code>.</li><li>Entre com a conta Microsoft que será o destino.</li><li>Aceite as permissões.</li><li>Copie o <code>Refresh Token</code> da página de callback.</li><li>Volte ao ImgBed e cole no campo correspondente.</li></ol><p><img src="'+i+`" alt="Refresh Token" loading="lazy"></p><h2 id="fluxo-rapido" tabindex="-1">Fluxo rápido <a class="header-anchor" href="#fluxo-rapido" aria-label="Permalink to &quot;Fluxo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Abrir portal.azure.com</span></span>
<span class="line"><span>-&gt; Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; App registrations</span></span>
<span class="line"><span>-&gt; New registration</span></span>
<span class="line"><span>-&gt; Configurar callback Web</span></span>
<span class="line"><span>-&gt; Copiar Application ID</span></span>
<span class="line"><span>-&gt; Criar Client Secret</span></span>
<span class="line"><span>-&gt; Adicionar permissões Microsoft Graph</span></span>
<span class="line"><span>-&gt; Preencher Client ID / Secret / Tenant ID no ImgBed</span></span>
<span class="line"><span>-&gt; Obter Token</span></span>
<span class="line"><span>-&gt; Colar Refresh Token e salvar</span></span></code></pre></div>`,29)])])}const C=d(l,[["render",p]]);export{v as __pageData,C as default};
